import { 
    SIGN_IN, 
    SIGN_OUT, 
    UPDATE_USER_INFO, 
    RESET_SIGN_IN_STATUS, 
    UPDATE_REPOS 
} from "../constants/actions/accountActionTypes";
import { IUserInfo, IRepo } from "../interfaces/IAccount";
import { updateErrorMsg } from "./editorActions";
import { saveAccessToken } from './../constants/DefaultSetting';
import { deepClone } from './../utils/deepClone';
import { ISite } from './../interfaces/ISetting';
import { CONFIG_BLOG_URL } from "../constants/Github";
import { updateBlogSha } from "./blogActions";

const githubApiUrl = 'https://api.github.com';

const $request = (url: string, token: string, 
    payload: any = null, method: string = 'GET',
    onSuccess: Function|null = null, onError: Function|null = null) => {
    const requestInit: any = {
        method: method,
        headers: new Headers({
            'Authorization': `token ${token}`,
            'Content-Type': 'application/json;charset=UTF-8',
            'Accept': 'application/vnd.github.v3+json'
        })
    };
    if (method.toLowerCase() != 'get' && payload) {
        const zanejs = (window as any).zanejs;
        if (zanejs.utils.isObject(payload)) {
            requestInit.body = JSON.stringify(payload);
        } else {
            requestInit.body = payload;
        }
    }
    fetch(url, requestInit).then((res) => {
        if (res.status == 200 || res.status == 201) {
            res.json()
                .then(data => onSuccess && onSuccess(data))
                .catch(err => onError && onError(err));
        } else {
            res.json()
                .then(data => onError && onError({
                    code: res.status,
                    message: data.message
                }))
                .catch(err => onError && onError(err));
        }
    });
};

export const signIn = (token: string) => {
    return (dispatch: Function, getState: Function) => {
        dispatch({type: `${SIGN_IN}_PENDING`});
        $request(
            `${githubApiUrl}/user`, 
            token, 
            null, 
            'GET', 
            (res: any) => {
                if (res.hasOwnProperty("name")) {
                    saveAccessToken(token);
                    dispatch(updateUserInfo({
                        token: token,
                        username: res.login,
                        nickname: res.name,
                        email: res.email,
                        repos: res.public_repos + res.total_private_repos,
                        avatarUrl: res.avatar_url,
                        createdAt: res.created_at,
                        updatedAt: res.updated_at
                    }));
                    dispatch({
                        type: `${SIGN_IN}_FULFILLED`
                    });
                    dispatch(getRepos());
                } else {
                    dispatch(updateErrorMsg(res.message));
                    dispatch({type: `${SIGN_IN}_REJECTED`});
                }
            },
            (res: any) => {
                dispatch({type: `${SIGN_IN}_REJECTED`});
            }
        );
    }
};

export const signOut = () => {
    return (dispatch: Function, getState: Function) => {
        saveAccessToken('');
        dispatch({type: SIGN_OUT});
    }
};

export const updateUserInfo = (userInfo: IUserInfo) => {
    return (dispatch: Function, getState: Function) => {
        dispatch({
            type: UPDATE_USER_INFO,
            payload: {
                userInfo
            }
        });
    }
};

const per_page = 100;
let cur_page = 1;
let cur_repos_num = 0;

/**
 * 获取所有仓库
 */
export const getRepos = () => {
    return (dispatch: Function, getState: Function) => {
        const state = getState();
        const siteInfo: ISite = state.setting.siteInfo;
        const userInfo: IUserInfo = state.account.userInfo;
        const repos: IRepo[] = deepClone(state.account.repos);
        if (userInfo) {
            $request(
                `${githubApiUrl}/user/repos?visibility=all&sort=updated&page=${cur_page}&per_page=${per_page}`, 
                userInfo.token, 
                null, 
                'GET', 
                (res: any) => {
                    const reposNum: number = res.length;
                    for (let i = 0; i < reposNum; ++i) {
                        const repo = res[i];
                        if (siteInfo && siteInfo.repo == repo.name) {
                            dispatch(getSiteBlogConfigContent());
                        }
                        repos.push({
                            name: repo.name,
                            language: repo.language

                        });
                    }
                    
                    dispatch({
                        type: UPDATE_REPOS,
                        payload: {
                            repos
                        }
                    });
                    cur_repos_num += reposNum;
                    if (cur_repos_num < userInfo.repos) {
                        dispatch(getRepos());
                    }
                }
            );
        }
    }
};

/**
 * 获取站点仓库内容
 */
export const getSiteBlogConfigContent = () => {
    return (dispatch: Function, getState: Function) => {
        const state = getState();
        const siteInfo: ISite = state.setting.siteInfo;
        if (siteInfo) {
            dispatch(getRepoContents(siteInfo.repo, CONFIG_BLOG_URL, 'master', (res: any) => {
                dispatch(updateBlogSha(res.sha));
            }));
        }
    }
};

/**
 * 获取仓库内容
 */
export const getRepoContents = (repo: string, path: string = '', ref: string = 'master', 
    onSuccess: Function|null = null, onError: Function|null = null) => {
    return (dispatch: Function, getState: Function) => {
        const state = getState();
        const userInfo: IUserInfo = state.account.userInfo;
        if (userInfo) {
            $request(
                `${githubApiUrl}/repos/${userInfo.username}/${repo}/contents/${path}?ref=${ref}`, 
                userInfo.token, 
                null, 
                'GET', 
                (res: any) => {
                    if (onSuccess) {
                        onSuccess(res);
                    }
                },
                (res: any) => {
                    if (onError) {
                        onError(res);
                    }
                }
            );
        }
    }
};

/**
 * 创建新文件或替换仓库中的现有文件。
 * @param message 
 * @param content 
 * @param sha 
 * @param branch 
 */
export const createOrUpdateFileContents = (repo: string, path: string, content: string, 
    sha: string, branch: string = 'master', onSuccess: Function|null = null, onError: Function|null = null) => {
    return (dispatch: Function, getState: Function) => {
        const state = getState();
        const userInfo: IUserInfo = state.account.userInfo;
        if (userInfo) {
            $request(
                `${githubApiUrl}/repos/${userInfo.username}/${repo}/contents/${path}`, 
                userInfo.token, 
                {
                    message: '本次提交来源于赞恩网站(zanejs.com)',
                    content,
                    sha,
                    branch,
                    committer: {
                        name: userInfo.nickname,
                        email: userInfo.email
                    }
                }, 
                'PUT', 
                (res: any) => {
                    if (onSuccess) {
                        onSuccess(res);
                    }
                },
                (res: any) => {
                    if (onError) {
                        onError(res);
                    }
                }
            );
        }
    }
};

