import * as React from "react";
import { Route, HashRouter as Router, Switch, RouteComponentProps } from 'react-router-dom';
import { IntlProvider, addLocaleData } from "react-intl";
import { connect } from "react-redux";
import { ISite } from "./interfaces/ISetting";
import { getSiteData } from "./actions/settingActions";

import zh from 'react-intl/locale-data/zh';
import en from 'react-intl/locale-data/en';
addLocaleData([...en, ...zh]);

const lazyLoader = (importComponent: any) => (
    class AsyncComponent extends React.Component {
        static Component: any = null;
        state = { C: AsyncComponent.Component };

        async componentDidMount() {
            const { default: C } = await importComponent();
            this.setState({ C });
        }

        render() {
            const { C } = this.state;
            return C ? React.createElement(C, this.props) : null;
        }
    }
);

// const history = createBrowserHistory();
const publicUrl = process.env.PUBLIC_URL;
const PageNotFound  = lazyLoader(() => import('./modules/404'));
const Home = lazyLoader(() => import('./modules/home'));
const Login = lazyLoader(() => import('./modules/account/Login'));

interface IState {

}

interface IProps {
    lang: string|undefined;
    siteInfo: ISite|null|undefined;
    i18n: any;
    getSiteData: Function;
}

const mapStateToProps = (state: any) => {
    return {
        lang: state.setting.lang,
        siteInfo: state.setting.siteInfo,
        i18n: state.setting.i18n,
    }
};

const mapDispatchTpProps = {
    getSiteData
};


class AppRouter extends React.Component<IProps, IState>{

    static instance: AppRouter | null = null;
    public intl: any;

    componentWillMount() {
        if (!AppRouter.instance) {
            AppRouter.instance = this;
        }
        this.props.getSiteData();
    }

    chooseLocale = () => {
        let i18n = this.props.siteInfo ? this.props.siteInfo.i18n : null;
        if (this.props.lang && i18n) {
            return i18n[this.props.lang];
        }
        return null;
    };

    render() {
        if (this.props.siteInfo) {
            document.title = this.props.siteInfo.title || '';

            let lang = this.props.lang;
            return (
                <IntlProvider
                    locale={lang}
                    messages={this.chooseLocale()}
                    ref={(ref: any) => this.intl = ref }>
                    <Router basename={publicUrl}>
                        <Switch>
                            <Route exact={true} path={`${publicUrl}/`} component={Home} />
                            <Route path={`${publicUrl}/login`} component={Login} />
                            <Route path={`${publicUrl}/404`} component={PageNotFound} />
                            <Route path={`${publicUrl}/:category?/:path?/:title?`} component={Home} />
                        </Switch>
                    </Router >
                </IntlProvider>
            );
        }
        return null;
    }
}
export default connect(mapStateToProps, mapDispatchTpProps)(AppRouter);

/**
 * 本地化
 * @param config
 */
export const formatMessage = (config: any) => {
    if (AppRouter.instance && AppRouter.instance.intl) {
        const { intl } = AppRouter.instance.intl.getChildContext();
        return intl.formatMessage(config);
    }
    if (config.defaultMessage) {
        return config.defaultMessage;
    }
    return '';
};
