import { Action, handleActions } from "redux-actions";
import { ISetting, ISettingPayload } from "../interfaces/ISetting";
import { WidgetPos_NONE } from "../constants/WidgetPos";
import { WidgetName_Blog_Explorer } from "../constants/WidgetNames";
import { 
    UPDATE_ACTIVE_PANEL, 
    UPDATE_MAX_WIDGET, 
    UPDATE_WIDGET, 
    UPDATE_SITE_INFO,
    UPDATE_TOOLBARS,
    UPDATE_MAIN_DOCK_PANEL_STYLE,
    UPDATE_LANGUAGE
} from "../constants/actions/settingActionTypes";
import {
    DEFAULT_LEFT_WIDGET_WIDTH, 
    DEFAULT_RIGHT_WIDGET_HEIGHT, 
    DEFAULT_BOTTOM_WIDGET_HEIGHT
} from "../constants/DefaultSetting";

const iniState: ISetting = {
    lang: 'zh',
    leftWidget: WidgetName_Blog_Explorer,
    leftWidgetWidth: DEFAULT_LEFT_WIDGET_WIDTH,
    rightWidget: null,
    rightWidgetWidth: DEFAULT_RIGHT_WIDGET_HEIGHT,
    bottomWidget: null,
    bottomWidgetHeight: DEFAULT_BOTTOM_WIDGET_HEIGHT,
    maxWidget: WidgetPos_NONE,
    activePanel: null,
    siteInfo: null,
    toolbars: null,
    mainDockPanelStyle: {
        "-moz-filter": "blur(10px)",
        "-ms-filter": "blur(10px)",
        "-o-filter": "blur(10px)",
        "filter": "blur(20px)",
        "opacity": 0.2,
        "background-image": "url(/assets/img/bg.jpg)",
        "background-position": "center top",
        "background-size": "cover",
        "background-color": "rgba(123, 123, 123, 0.35)",
        "background-blend-mode": "hue"
    }
};

export const settingReducer = handleActions<ISetting, ISettingPayload> ({
        [UPDATE_LANGUAGE]: (state: ISetting, action: Action<ISettingPayload>): ISetting => {
            return {
                ...state,
                lang: action.payload.lang
            }
        },
        [UPDATE_WIDGET]: (state: ISetting, action: Action<ISettingPayload>): ISetting => {
            return {
                ...state,
                ...action.payload
            }
        },
        [UPDATE_MAX_WIDGET]: (state: ISetting, action: Action<ISettingPayload>): ISetting => {
            return {
                ...state,
                maxWidget: action.payload.maxWidget
            }
        },
        [UPDATE_ACTIVE_PANEL]: (state: ISetting, action: Action<ISettingPayload>): ISetting => {
            return {
                ...state,
                activePanel: action.payload.activePanel
            }
        },
        [UPDATE_SITE_INFO] : (state: ISetting, action: Action<ISettingPayload>): ISetting => {
            return {
                ...state,
                siteInfo: action.payload.siteInfo
            }
        },
        [UPDATE_TOOLBARS] : (state: ISetting, action: Action<ISettingPayload>): ISetting => {
            return {
                ...state,
                toolbars: action.payload.toolbars
            }
        },
        [UPDATE_MAIN_DOCK_PANEL_STYLE] : (state: ISetting, action: Action<ISettingPayload>): ISetting => {
            return {
                ...state,
                mainDockPanelStyle: action.payload.mainDockPanelStyle
            }
        },
    },
    iniState
);