import { Action, handleActions } from "redux-actions";
import { IEditor, IEditorPayload } from "../interfaces/IEditor";
import {
    UPDATE_PANE_MAP,
    UPDATE_ERROR_MESSAGE,
    UPDATE_ACTIVE_PANE,
    UPDATE_MODAL_NAME
} from "../constants/actions/editorActionTypes";

const iniState: IEditor = {
    activePane: undefined,
    paneMap: null,
    errorMsg: undefined,
    currentModalName: undefined
};

export const editorReducer = handleActions<IEditor, IEditorPayload> ({
        
        [UPDATE_PANE_MAP]: (state: IEditor, action: Action<IEditorPayload>): IEditor => {
            return {
                ...state,
                paneMap: action.payload.paneMap
            }
        },
        [UPDATE_ACTIVE_PANE]: (state: IEditor, action: Action<IEditorPayload>): IEditor => {
            return {
                ...state,
                activePane: action.payload.activePane
            }
        },
        [UPDATE_ERROR_MESSAGE]: (state: IEditor, action: Action<IEditorPayload>): IEditor => {
            return {
                ...state,
                errorMsg: action.payload.errorMsg
            }
        },
        [UPDATE_MODAL_NAME]: (state: IEditor, action: Action<IEditorPayload>): IEditor => {
            return {
                ...state,
                currentModalName: action.payload.currentModalName
            }
        },
    },
    iniState
);