import * as React from "react";
import { IBlogNav } from "../../interfaces/IBlog";

export const generateTreeItemData = (item: IBlogNav, key: string) => {
    let reuslt: any = {
        key: key,
        title: item.title
    };
    if (item.children) {
        reuslt.closeIcon = `${process.env.PUBLIC_URL}/assets/svg/folder-public.svg`;
        reuslt.openIcon = `${process.env.PUBLIC_URL}/assets/svg/folder-public-open.svg`;
        reuslt.icon = generateTreeItemIcon;
        let children: any[] = [];
        item.children.map(($item: IBlogNav, index: number) => {
            children.push(generateTreeItemData($item, `${key}-${index}`));
        });
        reuslt.children = children;
    } else {
        reuslt.path = item.path;
        reuslt.sha = item.sha;
        reuslt.icon = <img src={`${process.env.PUBLIC_URL}/assets/svg/document.svg`} style={{marginTop: -5}} />;
    }
    return reuslt;
};

export const generateTreeItemIcon = (props: any) => {
    return <img src={props.expanded ? props.openIcon : props.closeIcon} style={{marginTop: -5}} />;
};